#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define BLOCK_SIZE 16

#define AA(i,j) a[offset*size+ (i)*size + (j) + offset]
#define BB(i,j) a[(i)*size + (j)]

__kernel void lud_diagonal(__global float *a,
                           __local float *local_a,
                           const int size,
                           const int offset) {
    int i, j, k;

    for (i = 0; i < BLOCK_SIZE; i++) {
        // Update diagonal block
        for (j = i; j < BLOCK_SIZE; j++) {
            float sum = AA(i,j);
            for (k = 0; k < i; k++) {
                sum -= AA(i,k) * AA(k,j);
            }
            AA(i,j) = sum;
        }

        float temp = 1.0f / AA(i,i);
        for (j = i + 1; j < BLOCK_SIZE; j++) {
            float sum = AA(j,i);
            for (k = 0; k < i; k++) {
                sum -= AA(j,k) * AA(k,i);
            }
            AA(j,i) = sum * temp;
        }
    }
}


__kernel void lud_perimeter(__global float *a,
                            __local float *local_diag,
                            __local float *local_peri,
                            __local float *local_peri2,
                            const int size,
                            const int offset) {
    int gid = get_global_id(0);
    int local_id = get_local_id(0);

    int size_inter = size - offset - BLOCK_SIZE;
    int chunks_in_inter_row = size_inter / BLOCK_SIZE;

    // Determine chunk index
    int chunk_idx = gid;

    if (chunk_idx >= chunks_in_inter_row) return;

    int i, j, k;
    int i_global = offset;
    int j_global = offset + BLOCK_SIZE * (chunk_idx + 1);

    // Load diagonal block to local memory (local_diag)
    for (i = local_id; i < BLOCK_SIZE * BLOCK_SIZE; i += get_local_size(0)) {
        local_diag[i] = a[(offset + i / BLOCK_SIZE) * size + offset + (i % BLOCK_SIZE)];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    // Update perimeter row
    for (j = 0; j < BLOCK_SIZE; j++) {
        for (i = 0; i < BLOCK_SIZE; i++) {
            float sum = 0.0f;
            for (k = 0; k < i; k++) {
                sum += local_diag[i * BLOCK_SIZE + k] * a[(i_global + k)*size + j_global + j];
            }
            int i_here = i_global + i;
            int j_here = j_global + j;
            a[i_here * size + j_here] = a[i_here * size + j_here] - sum;
        }
    }

    barrier(CLK_GLOBAL_MEM_FENCE | CLK_LOCAL_MEM_FENCE);

    // Update perimeter column
    i_global = offset + BLOCK_SIZE * (chunk_idx + 1);
    j_global = offset;

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (k = 0; k < j; k++) {
                sum += a[(i_global + i) * size + j_global + k] * local_diag[k * BLOCK_SIZE + j];
            }
            int i_here = i_global + i;
            int j_here = j_global + j;
            a[i_here * size + j_here] = (a[i_here * size + j_here] - sum) / local_diag[j * BLOCK_SIZE + j];
        }
    }
}

__kernel void lud_internal(__global float *a,
                           __local float *local_top,
                           __local float *local_left,
                           const int size,
                           const int offset) {
    int gid_x = get_global_id(0);
    int gid_y = get_global_id(1);

    int size_inter = size - offset - BLOCK_SIZE;
    int chunks_in_inter_row = size_inter / BLOCK_SIZE;

    if (gid_x >= chunks_in_inter_row || gid_y >= chunks_in_inter_row) return;

    int chunk_idx = gid_y * chunks_in_inter_row + gid_x;

    int i, j, k;
    float sum[BLOCK_SIZE];
    for (j = 0; j < BLOCK_SIZE; j++) {
        sum[j] = 0.0f;
    }

    int i_global = offset + BLOCK_SIZE * (1 + gid_y);
    int j_global = offset + BLOCK_SIZE * (1 + gid_x);

    int local_id = get_local_id(0);
    int local_size = get_local_size(0);

    // Load top block into local_top
    for (i = local_id; i < BLOCK_SIZE * BLOCK_SIZE; i += local_size) {
        int row = i / BLOCK_SIZE;
        int col = i % BLOCK_SIZE;
        local_top[i] = a[(offset + row) * size + j_global + col];
    }

    // Load left block into local_left
    for (i = local_id; i < BLOCK_SIZE * BLOCK_SIZE; i += local_size) {
        int row = i / BLOCK_SIZE;
        int col = i % BLOCK_SIZE;
        local_left[i] = a[(i_global + row) * size + offset + col];
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (k = 0; k < BLOCK_SIZE; k++) {
            float lval = local_left[i * BLOCK_SIZE + k];
            float *top_row = &local_top[k * BLOCK_SIZE];
            for (j = 0; j < BLOCK_SIZE; j++) {
                sum[j] += lval * top_row[j];
            }
        }
        for (j = 0; j < BLOCK_SIZE; j++) {
            int row = i_global + i;
            int col = j_global + j;
            a[row * size + col] -= sum[j];
            sum[j] = 0.0f;
        }
    }
}
